mapper.select:
select * from incidents
where status in ('ACTIVE','ESCALATED') and last_seen_at < #{cutoff}
order by last_seen_at asc limit #{limit}

select * from incidents

    and tenant_id = #{tenantId}and source_system = #{sourceSystem}
    and site_id = #{siteId}and plant_id = #{plantId}
    and object_type = #{objectType}and object_id = #{objectId}
    and event_type = #{eventType}and error_code = #{errorCode}
    and severity = #{severity}and status = #{status}

order by last_seen_at desc limit #{limit}
